const domainData = $json.body || {};
const records = domainData.data || [];

// Filter A records (resolving to IPv4 addresses)
const aRecords = records.filter(record => record.type === 'A');

// Map records to standard subdomain entries
return aRecords.map(record => ({
  json: {
    domain: domainData.domain,
    subdomain: `${record.subdomain}.${domainData.domain}`,
    ip: record.value
  }
}));

// Get persistent workflow static data
const staticData = $getWorkflowStaticData('global');

// Initialize history if not already present
if (!staticData.history) {
  staticData.history = {};
}

// Parse incoming asset data
const subdomain = $node["Parse Domain Records"].json.subdomain;
const ip = $node["Parse Domain Records"].json.ip;
const shodanData = $json.body || {};
const error = $json.error;

let currentPorts = [];
let currentVulns = [];

if (!error && shodanData.ports) {
  currentPorts = shodanData.ports;
  currentVulns = shodanData.vulns || [];
}

// Retrieve baseline state mapped by subdomain hostname
const lastState = staticData.history[subdomain] || { ports: [], vulns: [] };

// Risk profile parameters
const highRiskPorts = [21, 22, 23, 80, 443, 445, 3389, 8080];

// Calculate new exposures
const newPorts = currentPorts.filter(port => !lastState.ports.includes(port) && highRiskPorts.includes(port));
const newVulns = currentVulns.filter(vuln => !lastState.vulns.includes(vuln));

const hasThreat = newPorts.length > 0 || newVulns.length > 0;

// Update history baseline mapped by subdomain
staticData.history[subdomain] = {
  ports: currentPorts,
  vulns: currentVulns
};

return {
  json: {
    subdomain,
    ip,
    hasThreat,
    newPorts,
    newVulns,
    allPorts: currentPorts,
    allVulns: currentVulns
  }
};

